Here's the complete implementation using the Hexi library:

```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    hexi::Reader reader(buffer);
    NetworkPacket packet;

    // Read packet_id
    reader.read(packet.packet_id);

    // Read username using length prefix
    reader.read(hexi::prefixed(packet.username));

    // Read scores vector using container adaptor
    reader.read(hexi::read_container(packet.scores));

    // Read metadata as null-terminated string for zero-copy
    reader.read(hexi::null_terminated(packet.metadata));

    // Skip any remaining padding bytes
    reader.skip(reader.remaining());

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    hexi::Reader reader(buffer);
    PacketInfo info;

    // Use span() to get zero-copy view of packet_id (first 4 bytes)
    auto packet_id_span = reader.span(sizeof(uint32_t));
    info.packet_id = *reinterpret_cast<const uint32_t*>(packet_id_span.data());

    // Read username using prefixed adaptor to get string_view
    std::string_view username_view;
    reader.read(hexi::prefixed(username_view));
    info.username = username_view;

    // Skip scores vector without reading elements
    uint32_t score_count;
    reader.read(score_count);  // Read the count first
    reader.skip(score_count * sizeof(uint32_t));  // Skip the actual score data

    return info;
}
```

