#include <vector>
#include <cstdint>
#include <cstddef>

const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    // Return pointer to the beginning of the buffer for reading
    return buffer.empty() ? nullptr : buffer.data();
}

uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    // Return pointer to the end of the buffer for writing
    // This allows appending new data
    return buffer.empty() ? nullptr : const_cast<uint8_t*>(buffer.data() + buffer.size());
}

