    size_t readable_size;
    size_t free_space;
};

BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    BufferInfo info;

    // Readable size is the current size of the buffer
    info.readable_size = buffer.size();

    // Free space depends on the buffer's capacity vs current size
    // For a vector, this is capacity - size
    info.free_space = buffer.capacity() - buffer.size();

    return info;
}
