#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>

struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result;

    // Create buffer adaptor for previewing
    hexi::buffer_adaptor adaptor(buffer.data(), buffer.size());

    // Preview the first byte (data_type) without advancing read pointer
    if (adaptor.size() < 1) {
        // Not enough data for data_type
        return result;
    }

    uint8_t data_type = adaptor.peek<uint8_t>();
    result.data_type = data_type;

    // Check if we have enough data for header (data_type + item_count)
    if (adaptor.size() < 5) { // 1 byte for data_type + 4 bytes for item_count
        return result;
    }

    // Now use binary_stream to read the data
    hexi::binary_stream stream(buffer.data(), buffer.size());

    // Read data_type (this will advance the pointer)
    stream >> result.data_type;

    // Read item_count
    uint32_t item_count;
    stream >> item_count;

    // Calculate required size for items
    size_t required_size = 0;
    if (data_type == 0) { // integers
        required_size = item_count * sizeof(uint32_t);
    } else if (data_type == 1) { // floats
        required_size = item_count * sizeof(float);
    } else {
        // Unknown data type
        return result;
    }

    // Check if we have enough data for all items
    if (stream.size() < required_size) {
        return result;
    }

    // Read items based on data type
    if (data_type == 0) {
        // Read integers
        result.int_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.int_items[i];
        }
    } else if (data_type == 1) {
        // Read floats
        result.float_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.float_items[i];
        }
    }

    return result;
}
