template<size_t block_size = 1024>
std::vector<uint8_t> peek_data_from_buffer(const hexi::dynamic_buffer<block_size>& buffer, size_t bytes_to_peek) {
    // Get the available data size
    size_t available_bytes = buffer.size();

    // Adjust bytes_to_peek to not exceed available data
    bytes_to_peek = std::min(bytes_to_peek, available_bytes);

    // Create result vector with the appropriate size
    std::vector<uint8_t> result;
    result.reserve(bytes_to_peek);

    // Create a temporary copy of the buffer to read from without modifying the original
    hexi::dynamic_buffer<block_size> temp_buffer = buffer;

    // Read the data from the temporary buffer
    for (size_t i = 0; i < bytes_to_peek; ++i) {
        uint8_t byte;
        if (temp_buffer.pop(byte)) {
            result.push_back(byte);
        } else {
            // This shouldn't happen since we checked available_bytes, but handle gracefully
            break;
        }
    }

    return result;
}
```

