#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>
#include <vector>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    using namespace hexi;

    // Create a block allocator that manages blocks of size 64 bytes
    block_allocator<64, element_count> allocator;

    std::cout << "=== Block Allocator Free List Demonstration ===\n";
    std::cout << "Block size: 64 bytes\n";
    std::cout << "Total blocks: " << element_count << "\n\n";

    // Vector to track allocated blocks
    std::vector<void*> allocated_blocks;

    // Phase 1: Allocate all available blocks
    std::cout << "Phase 1: Allocating all " << element_count << " blocks...\n";
    for (size_t i = 0; i < element_count; ++i) {
        void* block = allocator.allocate(64);
        if (block) {
            allocated_blocks.push_back(block);
            std::cout << "Allocated block " << i + 1 << " at address: " << block << "\n";
        }
    }

    // Phase 2: Deallocate blocks in reverse order (simulating LIFO behavior)
    std::cout << "\nPhase 2: Deallocating blocks in reverse order...\n";
    while (!allocated_blocks.empty()) {
        void* block = allocated_blocks.back();
        allocator.deallocate(block);
        allocated_blocks.pop_back();
        std::cout << "Deallocated block at address: " << block << "\n";
    }

    // Phase 3: Re-allocate to observe free list LIFO behavior
    std::cout << "\nPhase 3: Re-allocating blocks (should follow LIFO order)...\n";
    for (size_t i = 0; i < std::min(element_count, size_t(5)); ++i) {
        void* block = allocator.allocate(64);
        if (block) {
            std::cout << "Re-allocated block " << i + 1 << " at address: " << block << "\n";
            // Keep track for final cleanup
            allocated_blocks.push_back(block);
        }
    }

    // Phase 4: Demonstrate mixed allocation/deallocation pattern
    std::cout << "\nPhase 4: Mixed allocation/deallocation pattern...\n";

    // Allocate some blocks
    std::vector<void*> temp_blocks;
    for (size_t i = 0; i < 3; ++i) {
        void* block = allocator.allocate(64);
        if (block) {
            temp_blocks.push_back(block);
            std::cout << "Allocated temp block " << i + 1 << " at: " << block << "\n";
        }
    }

    // Deallocate middle block first
    if (temp_blocks.size() > 1) {
        allocator.deallocate(temp_blocks[1]);
        std::cout << "Deallocated middle block at: " << temp_blocks[1] << "\n";
        temp_blocks.erase(temp_blocks.begin() + 1);
    }

    // Allocate again - should get the recently freed block (LIFO)
    void* new_block = allocator.allocate(64);
    if (new_block) {
        std::cout << "New allocation got address: " << new_block << " (likely same as deallocated middle block)\n";
        temp_blocks.push_back(new_block);
    }

    // Cleanup
    for (void* block : temp_blocks) {
        allocator.deallocate(block);
    }
    for (void* block : allocated_blocks) {
        allocator.deallocate(block);
    }

    std::cout << "\n=== Demonstration Complete ===\n";
    std::cout << "Key observations:\n";
    std::cout << "1. push() adds blocks to the head of free list (LIFO behavior)\n";
    std::cout << "2. pop() removes blocks from the head of free list\n";
    std::cout << "3. Recent deallocations are the first to be re-allocated\n";
    std::cout << "4. Free list maintains a singly-linked list of available blocks\n";
}

// Example usage
int main() {
    demonstrate_block_allocator_behavior<10>();
    return 0;
}
```

This implementation demonstrates how the `block_allocator` internally manages its free list using `push()` and `pop()` operations:

1. **Phase 1**: Allocates all available blocks to show the initial state
2. **Phase 2**: Deallocates blocks in reverse order, simulating how `push()` adds blocks to the head of the free list
3. **Phase 3**: Re-allocates blocks to demonstrate the LIFO (Last-In-First-Out) behavior of the free list
4. **Phase 4**: Shows a mixed pattern where a middle block is deallocated and then re-allocated, demonstrating that the most recently freed block is the first to be allocated again

The code includes comprehensive comments and output to clearly illustrate the internal free list management behavior of the block allocator.

