        }
    }

    // Deallocate middle block first
    if (temp_blocks.size() > 1) {
        allocator.deallocate(temp_blocks[1]);
        std::cout << "Deallocated middle block at: " << temp_blocks[1] << "\n";
        temp_blocks.erase(temp_blocks.begin() + 1);
    }

    // Allocate again - should get the recently freed block (LIFO)
    void* new_block = allocator.allocate(64);
    if (new_block) {
        std::cout << "New allocation got address: " << new_block << " (likely same as deallocated middle block)\n";
        temp_blocks.push_back(new_block);
    }

    // Cleanup
    for (void* block : temp_blocks) {
        allocator.deallocate(block);
    }
    for (void* block : allocated_blocks) {
        allocator.deallocate(block);
    }

    std::cout << "\n=== Demonstration Complete ===\n";
    std::cout << "Key observations:\n";
    std::cout << "1. push() adds blocks to the head of free list (LIFO behavior)\n";
    std::cout << "2. pop() removes blocks from the head of free list\n";
    std::cout << "3. Recent deallocations are the first to be re-allocated\n";
    std::cout << "4. Free list maintains a singly-linked list of available blocks\n";
}

