Here's the complete implementation using the Hexi library's `file_buffer`:

```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    // Create a file_buffer object for reading
    hexi::file_buffer file(file_path.string(), "rb");

    // Get the actual readable size (minimum of requested bytes and available bytes)
    size_t actual_size = std::min(bytes_to_read, file.size());

    // Create destination buffer
    std::vector<uint8_t> buffer(actual_size);

    // Read data from file into buffer
    if (actual_size > 0) {
        file.read(reinterpret_cast<char*>(buffer.data()), actual_size);
    }

    return buffer;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    // Create a file_buffer object for reading
    hexi::file_buffer file(file_path.string(), "rb");

    // Get current position to restore later
    size_t original_pos = file.tell();

    // Get the actual preview size (minimum of requested bytes and available bytes)
    size_t actual_size = std::min(bytes_to_preview, file.size() - original_pos);

    // Create destination buffer
    std::vector<uint8_t> buffer(actual_size);

    // Read data without advancing pointer (read and then seek back)
    if (actual_size > 0) {
        file.read(reinterpret_cast<char*>(buffer.data()), actual_size);
        file.seek(original_pos); // Restore original position
    }

    return buffer;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    // Create a file_buffer object for writing (creates file if it doesn't exist)
    hexi::file_buffer file(file_path.string(), "wb");

    // Write data to file
    if (!data.empty()) {
        file.write(reinterpret_cast<const char*>(data.data()), data.size());
    }
}

size_t get_file_size(const std::filesystem::path& file_path) {
    // Create a file_buffer object for reading
    hexi::file_buffer file(file_path.string(), "rb");

    // Return the size of readable data in the file
    return file.size();
}
