    std::vector<uint8_t> result;

    // Determine how many bytes we can actually read (don't exceed buffer size)
    size_t actual_bytes_to_read = std::min(bytes_to_read, buffer.size());

    // Read data from buffer
    for (size_t i = 0; i < actual_bytes_to_read; ++i) {
        result.push_back(static_cast<uint8_t>(buffer[i]));
    }

    return result;
}
