#include <vector>

struct PaddedData {
    uint16_t header;
    std::string data;
    uint32_t footer;
};

std::vector<uint8_t> serialize_with_padding(const PaddedData& packet) {
    hexi::Writer writer;

    // Write header
    writer.write(packet.header);

    // Write data with length prefix
    writer.write_string(packet.data);

    // Write 16 bytes of padding filled with 0x00
    writer.fill<16>(0x00);

    // Write footer
    writer.write(packet.footer);

    return writer.data();
}

