    }

    // Create read adaptor and read data back from buffer
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer.data(), buffer.size());

    // Check readable size
    std::vector<uint8_t> result;
    if (read_adaptor.size() > 0) {
