std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // Create read adaptor for the buffer data
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer_data.data(), buffer_data.size());

    std::vector<uint8_t> peeked_data;

    // Use read_ptr() to get pointer to current read position
    const uint8_t* read_ptr = static_cast<const uint8_t*>(read_adaptor.read_ptr());

    // Use copy() to peek at data without moving read cursor
    if (read_adaptor.size() >= peek_size) {
        peeked_data.resize(peek_size);
        read_adaptor.copy(peeked_data.data(), peek_size);
    } else {
        // If peek_size is larger than available data, peek only what's available
        peeked_data.resize(read_adaptor.size());
        if (!peeked_data.empty()) {
            read_adaptor.copy(peeked_data.data(), peeked_data.size());
        }
    }

    // Now actually consume the data using read()
    std::vector<uint8_t> consumed_data;
    std::size_t read_size = (peek_size <= read_adaptor.size()) ? peek_size : read_adaptor.size();
    if (read_size > 0) {
        consumed_data.resize(read_size);
        read_adaptor.read(consumed_data.data(), read_size);
    }

    return peeked_data;
}

